        # ─── BÖLGE 4: Toulmin Rebuttal (UYGUN_DEĞİL / ŞÜPHELİ) ─
        if verdict_kisa in ("UYGUN DEĞİL", "ŞÜPHELİ"):
            sebep_atomlari = []
            for s in sartlar:
                g = s.get("grup", "") or ""
