        for i, k in enumerate(["ARB_MONO", "ARB_KOMBI"], start=bas2 + 1):
            ws1.cell(row=i, column=1, value=k).font = Font(bold=True)
            ws1.cell(row=i, column=2, value=kategori_sayac.get(k, 0)
                     ).alignment = Alignment(horizontal="center")
