            ("rap_doz",          "Rapor Doz",       14),
            ("kutu",             "Kutu",            6),
            ("msj",              "Msj",             7),
            ("rec_turu",         "Reç.Türü",        10),
            ("rec_alt_turu",     "Reç.Alt",         10),
