            ("yas",              "Yaş",             6),
            ("cins",             "Cin.",            6),
            ("doktor",           "Doktor",          22),
            ("brans",            "Branş",           20),
            ("kurum_adi",        "Kurum",           28),
            ("ilac",             "İlaç",            28),
            ("etkin",            "Etken Madde",     22),
